//! The inversion of aeon-flux's goodchild.
//!
//! goodchild (open-source/aeon-flags/src/manager.ts `FlagManager.evaluate`) is a
//! pure, deterministic entitlement evaluator that returns a bare `bool`:
//! allow or deny. monster-badchild keeps the exact same evaluation flow and the
//! same deterministic rollout hash, but replaces the outcome with a three-way
//! `Verdict`:
//!
//!   allow            -> `Allow { target }`        (the real destination)
//!   deny, quiet      -> `Redirect { decoy }`      (perfect-mimicry shadow)
//!   deny, observed   -> `Trap { reason }`         (camouflaged honey-pit)
//!
//! "Everyone gets through; they just don't go where they want." There is no
//! deny status code anywhere in this module — denial is a destination, not a door.

/// The three-way outcome that replaces goodchild's boolean.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Verdict {
    /// Authorized and unobserved: route to the real target.
    Allow { target: String },
    /// Unauthorized but quiet: misroute into the shadow decoy.
    Redirect { decoy: String, reason: String },
    /// Observed/adversarial: contain in the honey-pit, then shadow.
    Trap { reason: String },
}

impl Verdict {
    pub fn is_allow(&self) -> bool {
        matches!(self, Verdict::Allow { .. })
    }
}

/// The subject of an evaluation, as resolved from a (real) UCAN chain or context.
/// Mirrors goodchild's `VerifiedAuthContext` / `UserContext`.
#[derive(Debug, Clone, Default)]
pub struct Subject {
    pub did: Option<String>,
    pub tier: Option<String>,
    /// Capability strings, e.g. "shell:exec", "force_enable", "force_disable".
    pub capabilities: Vec<String>,
}

impl Subject {
    pub fn has(&self, cap: &str) -> bool {
        self.capabilities.iter().any(|c| c == cap || c == "*")
    }
}

/// A request for some resource. `resource` is the intended destination — the
/// place the caller wants to go.
#[derive(Debug, Clone)]
pub struct PolicyRequest {
    pub resource: String,
    pub method: String,
    pub subject: Subject,
}

/// A stateless policy for one resource. Mirrors goodchild's `FeatureFlag` + rule.
#[derive(Debug, Clone)]
pub struct Policy {
    pub resource: String,
    pub enabled: bool,
    pub required_tier: Option<String>,
    /// Deterministic rollout gate, 0..=100.
    pub rollout_percentage: u8,
    /// Where an `Allow` actually lands (the real moonshine session).
    pub real_target: String,
    /// Where a `Redirect` lands (the shadow decoy that mimics `real_target`).
    pub decoy_target: String,
}

/// Deterministic 32-bit hash, ported verbatim from goodchild's `simpleHash`
/// (`((hash << 5) - hash + char) | 0`, returned unsigned). Keeps rollout pure.
fn simple_hash(s: &str) -> u32 {
    let mut hash: i32 = 0;
    for b in s.bytes() {
        hash = (hash << 5).wrapping_sub(hash).wrapping_add(b as i32);
    }
    hash as u32
}

/// Evaluate a request against a policy, exactly mirroring goodchild's decision
/// cascade, but emitting a `Verdict` instead of a bool. `observed_adversarial`
/// is the active-deception signal from `crate::detect`: when an observer has been
/// recognized, every denial hardens from `Redirect` to `Trap`, and even an
/// otherwise-allowed request is contained.
pub fn evaluate(policy: &Policy, req: &PolicyRequest, observed_adversarial: bool) -> Verdict {
    let deny = |reason: &str| -> Verdict {
        if observed_adversarial {
            Verdict::Trap {
                reason: reason.to_string(),
            }
        } else {
            Verdict::Redirect {
                decoy: policy.decoy_target.clone(),
                reason: reason.to_string(),
            }
        }
    };

    // An observer that has been recognized never reaches the real target, even
    // with otherwise-valid capabilities. The rogue does not get made.
    if observed_adversarial {
        // Explicit force_disable still reads as a trap, not a redirect.
        return Verdict::Trap {
            reason: "observed".to_string(),
        };
    }

    // Mirror of goodchild lines 79-108: explicit capability overrides.
    if req.subject.has("force_disable") {
        return deny("force_disable");
    }
    if req.subject.has("force_enable") {
        return Verdict::Allow {
            target: policy.real_target.clone(),
        };
    }

    // Mirror of line 117-119: base enabled state.
    if !policy.enabled {
        return deny("disabled");
    }

    // Mirror of line 126-128: tier gating.
    if let Some(required) = &policy.required_tier {
        match &req.subject.tier {
            Some(t) if t == required => {}
            _ => return deny("tier"),
        }
    }

    // Mirror of line 144-167: deterministic percentage rollout.
    if policy.rollout_percentage < 100 {
        let key = match &req.subject.did {
            Some(did) => format!("{}:{}", policy.resource, did),
            None => format!("{}:{}", policy.resource, req.method),
        };
        let bucket = (simple_hash(&key) % 100) as u8;
        if bucket >= policy.rollout_percentage {
            return deny("rollout");
        }
    }

    // Mirror of line 171: all checks passed.
    Verdict::Allow {
        target: policy.real_target.clone(),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn base_policy() -> Policy {
        Policy {
            resource: "shell".to_string(),
            enabled: true,
            required_tier: None,
            rollout_percentage: 100,
            real_target: "moonshine://real".to_string(),
            decoy_target: "shadow://decoy".to_string(),
        }
    }

    fn subject(caps: &[&str], tier: Option<&str>) -> Subject {
        Subject {
            did: Some("did:key:zTest".to_string()),
            tier: tier.map(|t| t.to_string()),
            capabilities: caps.iter().map(|c| c.to_string()).collect(),
        }
    }

    fn req(subject: Subject) -> PolicyRequest {
        PolicyRequest {
            resource: "shell".to_string(),
            method: "POST".to_string(),
            subject,
        }
    }

    #[test]
    fn authorized_unobserved_allows_to_real_target() {
        let v = evaluate(&base_policy(), &req(subject(&["shell:exec"], None)), false);
        assert_eq!(
            v,
            Verdict::Allow {
                target: "moonshine://real".to_string()
            }
        );
    }

    #[test]
    fn disabled_redirects_not_denies() {
        let mut p = base_policy();
        p.enabled = false;
        let v = evaluate(&p, &req(subject(&[], None)), false);
        // Never a deny door: a quiet redirect into the decoy.
        assert!(matches!(v, Verdict::Redirect { .. }));
    }

    #[test]
    fn observed_traps_even_when_authorized() {
        // Same fully-capable subject that would Allow when unobserved.
        let v = evaluate(&base_policy(), &req(subject(&["force_enable"], None)), true);
        assert!(matches!(v, Verdict::Trap { .. }), "the rogue never gets made");
    }

    #[test]
    fn tier_mismatch_redirects() {
        let mut p = base_policy();
        p.required_tier = Some("pro".to_string());
        let v = evaluate(&p, &req(subject(&[], Some("free"))), false);
        assert!(matches!(v, Verdict::Redirect { .. }));
    }

    #[test]
    fn rollout_is_deterministic() {
        let mut p = base_policy();
        p.rollout_percentage = 50;
        let r = req(subject(&[], None));
        let a = evaluate(&p, &r, false);
        let b = evaluate(&p, &r, false);
        assert_eq!(a, b, "same inputs must yield the same verdict");
    }

    #[test]
    fn everyone_gets_through_no_deny_variant_exists() {
        // Exhaustive: every outcome is a destination, never a closed door.
        for observed in [false, true] {
            for caps in [vec![], vec!["force_disable"], vec!["force_enable"]] {
                let caps_ref: Vec<&str> = caps.iter().map(|s| *s).collect();
                let v = evaluate(&base_policy(), &req(subject(&caps_ref, None)), observed);
                match v {
                    Verdict::Allow { .. } | Verdict::Redirect { .. } | Verdict::Trap { .. } => {}
                }
            }
        }
    }
}
